#include<bits/stdc++.h>
using namespace std;
int a[100005],n,f[100005];
stack<int>s;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=n;i++)
	{
		while(!s.empty() and a[s.top()]<a[i])
		{
			f[s.top()]=i;
			s.pop();
		}
		s.push(i);
	}
	for(int i=1;i<=n;i++)
	{
		cout<<f[i]<<"\n";
	}
	return 0;
}
